#include <iostream>
using namespace std;

// Function template:
template<typename T>
T maxOf(T a, T b) { return a > b ? a : b; }

cout << maxOf(3,7) << endl;      // 7 (int)
cout << maxOf(3.1,2.9) << endl; // 3.1 (double)
cout << maxOf('z','a') << endl; // z (char)

// Class template:
template<typename T>
class Box {
    T value;
public:
    Box(T v):value(v){}
    T get() const { return value; }
};

Box<int> ib(42);
Box<string> sb("hello");
cout << ib.get() << " " << sb.get();

